import React from "react";

export default function Logo() {
  return (
    <div className="min-h-screen flex flex-col items-center justify-center px-4 
                    bg-gradient-to-br from-pink-300 via-purple-200 to-cyan-200">
      <div className="relative flex flex-col items-center">
        {/* Animated Rotating Frame */}
        <div className="absolute w-52 h-52 md:w-72 md:h-72 rounded-full border-4 border-pink-400
                        animate-spin-slow"></div>

        {/* Mascot */}
        <img
          src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/nm4j1a3y_expires_30_days.png"
          alt="Mascot"
          className="w-48 h-48 md:w-64 md:h-64 z-10 rounded-full shadow-lg"
        />

        {/* Text "vasco" */}
        <span className="absolute text-pink-400 text-6xl md:text-9xl font-bold z-20">
          vasco
        </span>
      </div>

      {/* Slogan */}
      <div className="mt-8 text-center">
        <h1 className="text-xl md:text-2xl font-semibold text-gray-800">
          Kết nối - Học tập - Giải trí - Sáng tạo
        </h1>
        <p className="text-sm text-gray-600 mt-2">By: KBKHC</p>
      </div>
    </div>
  );
}
